#include <iostream>
#include <stack>
using namespace std;
class Solution {
public:
    bool validateQueue(string s) {
        stack stack;
        for (char c : s) {
            if (c == ',') {
                if (!stack.empty()) stack.pop();
            } else stack.push(c);
        }
        return stack.size() == 1;
    }
};
#define int long long
signed main() {
    int t;
    cin >> t;
    for (int i = 0; i < t; ++i) {
        string s;
        cin >> s;
        cout << (Solution().validateQueue(s) ? "Yes" : "No") << endl;
    }
    return 0;
}
